public static long solve(long[] nums, long[][] queries) {
    final long MOD = (long) (109 + 7);
    int n = nums.length;
    long[] result = new long[n];
    for (int i = 0; i < n; i++) {
        result[i] = nums[i];
    }

    for (long[] query : queries) {
        int li = (int) query[0];
        int ri = (int) query[1];
        long ki = query[2];
        long vi = query[3];
        int idx = li;
        while (idx <= ri) {
            result[idx] = (result[idx] * vi) % MOD;
            idx += (int) ki;
        }
    }

    long xorResult = 0;
    for (long num : result) {
        xorResult ^= num;
    }
    return xorResult;
}
